1	type Item = { type: string; cursed?: boolean; enchantment?: number };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	const DEDUCTIBLE = 100;
11	const CAP_MULTIPLIER = 2;
12	
13	const MAIN_ITEM_INSURANCE_VALUE: Record<string, number> = {
14	  sword: 1000,
15	  amulet: 600,
16	};
17	
18	const COMPONENT_INSURANCE_VALUE = 250;
19	
20	const itemInsuranceValue = (item: Item): number =>
21	  MAIN_ITEM_INSURANCE_VALUE[item.type] ?? COMPONENT_INSURANCE_VALUE;
22	
23	const PROCESSING_FEE = 5;
24	const FIRST_INSURANCE_SURCHARGE = 0.1;
25	const CURSE_SURCHARGE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const LOYALTY_DISCOUNT = 0.2;
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const FOLLOWUP_DISCOUNT = 0.15;
31	const COMPONENT_BASE_PREMIUM = 25;
32	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
33	const COMPONENT_BLOCK_SIZE = 3;
34	
35	const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
36	  sword: 100,
37	  amulet: 60,
38	};
39	
40	const isMainItem = (item: Item): boolean => item.type in MAIN_ITEM_BASE_PREMIUM;
41	
42	const ceilWithEpsilon = (n: number): number => Math.ceil(Math.round(n * 1e8) / 1e8);
43	
44	const rateAmount = (base: number, applies: boolean, rate: number): number =>
45	  applies ? base * rate : 0;
46	
47	const isHighlyEnchanted = (item: Item): boolean =>
48	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
49	
50	const mainItemBase = (item: Item): number => MAIN_ITEM_BASE_PREMIUM[item.type];
51	
52	const mainItemSurcharges = (item: Item): number => {
53	  const base = mainItemBase(item);
54	  return (
55	    rateAmount(base, item.cursed === true, CURSE_SURCHARGE) +
56	    rateAmount(base, isHighlyEnchanted(item), HIGH_ENCHANTMENT_SURCHARGE)
57	  );
58	};
59	
60	const componentGroupBase = (count: number): number => {
61	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
62	  const leftover = count % COMPONENT_BLOCK_SIZE;
63	  return blocks * COMPONENT_BLOCK_BASE_PREMIUM + leftover * COMPONENT_BASE_PREMIUM;
64	};
65	
66	const componentCountsByType = (components: Item[]): Map<string, number> => {
67	  const counts = new Map<string, number>();
68	  for (const item of components) {
69	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
70	  }
71	  return counts;
72	};
73	
74	const sumComponentGroupBases = (components: Item[]): number =>
75	  [...componentCountsByType(components).values()].reduce(
76	    (total, count) => total + componentGroupBase(count),
77	    0,
78	  );
79	
80	const partitionItems = (items: Item[]): { mainItems: Item[]; components: Item[] } => {
81	  const mainItems: Item[] = [];
82	  const components: Item[] = [];
83	  for (const item of items) {
84	    (isMainItem(item) ? mainItems : components).push(item);
85	  }
86	  return { mainItems, components };
87	};
88	
89	const sumMainItemBases = (mainItems: Item[]): number =>
90	  mainItems.reduce((sum, item) => sum + mainItemBase(item), 0);
91	
92	const sumMainItemSurcharges = (mainItems: Item[]): number =>
93	  mainItems.reduce((sum, item) => sum + mainItemSurcharges(item), 0);
94	
95	const isLoyalCustomer = (customer: Customer): boolean =>
96	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
97	
98	const totalDiscount = (policyBase: number, customer: Customer, isFollowUp: boolean): number =>
99	  rateAmount(policyBase, isLoyalCustomer(customer), LOYALTY_DISCOUNT) +
100	  rateAmount(policyBase, isFollowUp, FOLLOWUP_DISCOUNT);
101	
102	const priceQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
103	  const { mainItems, components } = partitionItems(step.items);
104	  const policyBase = sumMainItemBases(mainItems) + sumComponentGroupBases(components);
105	  const surcharges = sumMainItemSurcharges(mainItems);
106	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE;
107	  const discounts = totalDiscount(policyBase, customer, isFollowUp);
108	  return {
109	    premium: ceilWithEpsilon(policyBase + surcharges + firstInsurance - discounts + PROCESSING_FEE),
110	  };
111	};
112	
113	const countQuotesBefore = (steps: Step[], index: number): number =>
114	  steps.slice(0, index).filter((s) => s.op === "quote").length;
115	
116	const insuranceSumOf = (step: QuoteStep): number =>
117	  step.items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
118	
119	const damagePayout = (damage: Damage): number =>
120	  Math.max(0, damage.amount - DEDUCTIBLE);
121	
122	const totalPayout = (damages: Damage[]): number =>
123	  damages.reduce((sum, d) => sum + damagePayout(d), 0);
124	
125	const processClaim = (step: ClaimStep, steps: Step[]): { payout: number; remainingCap: number } => {
126	  const policyStep = steps[step.policy] as QuoteStep;
127	  const cap = CAP_MULTIPLIER * insuranceSumOf(policyStep);
128	  const payout = totalPayout(step.incident.damages);
129	  return { payout, remainingCap: cap - payout };
130	};
131	
132	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
133	  results: scenario.steps.map((step, i) =>
134	    step.op === "quote"
135	      ? priceQuote(step, scenario.customer, countQuotesBefore(scenario.steps, i) > 0)
136	      : processClaim(step, scenario.steps),
137	  ),
138	});
